  "why.vision.eyebrow": {
    "en": "Vision",
    "es": "Visión"
  },
  "why.vision.title": {
    "en": "To become the leading international advisory platform for digital infrastructure, project structuring and AI-enabled investment intelligence.",
    "es": "Convertirse en la plataforma internacional de asesoría líder en infraestructura digital, estructuración de proyectos e inteligencia de inversión habilitada por IA."
  },
  "why.vision.p1": {
    "en": "International Network Advisors (INA) was conceived with a clear ambition: to redefine how governments, development banks, investors and technology companies identify, structure, finance and implement digital infrastructure projects.",
    "es": "International Network Advisors (INA) fue concebida con una ambición clara: redefinir cómo los gobiernos, bancos de desarrollo, inversores y empresas tecnológicas identifican, estructuran, financian e implementan proyectos de infraestructura digital."
  },
  "why.vision.p2": {
    "en": "Digital infrastructure is no longer limited to telecommunications networks. It now encompasses fiber optic backbones, submarine cable systems, hyperscale data centers, cloud infrastructure, artificial intelligence computing facilities, satellite constellations, smart energy systems and the digital ecosystems that support modern economies.",
    "es": "La infraestructura digital ya no se limita a las redes de telecomunicaciones. Hoy abarca redes troncales de fibra óptica, sistemas de cables submarinos, data centers hyperscale, infraestructura en la nube, instalaciones de cómputo de inteligencia artificial, constelaciones satelitales, sistemas energéticos inteligentes y los ecosistemas digitales que sostienen a las economías modernas."
  },
  "why.vision.p3": {
    "en": "Unlike traditional consulting firms, INA is designed from the ground up as an intellectual property company. Its competitive advantage is not based solely on consulting services but on proprietary methodologies, assessment models, digital tools and AI-powered advisory capabilities that can be reused across projects and jurisdictions.",
    "es": "A diferencia de las consultoras tradicionales, INA está diseñada desde su origen como una empresa de propiedad intelectual. Su ventaja competitiva no se basa únicamente en servicios de consultoría, sino en metodologías propias, modelos de evaluación, herramientas digitales y capacidades de asesoría potenciadas por IA que pueden reutilizarse en distintos proyectos y jurisdicciones."
  },
