  "fw.f1.kicker": {
    "en": "AI-Powered Methodology",
    "es": "Metodología Potenciada por IA"
  },
  "fw.f1.overview": {
    "en": "INA's proprietary methodology for structuring, governing and implementing complex communications and data infrastructure projects &mdash; submarine cable systems, backbone and last-mile fiber, Fixed Wireless Access (FWA) deployments, and datacenters built for AI workloads. It is designed to apply in the same way to a public agency, a private company, an operator consortium, or a mixed-capital investment vehicle, and incorporates generative AI agents as a constitutive part of its architecture &mdash; one specialized agent per phase &mdash; always under a permanent human-in-the-loop principle.",
    "es": "La metodología propia de INA para estructurar, gobernar e implementar proyectos complejos de infraestructura de comunicaciones y datos &mdash; sistemas de cables submarinos, fibra troncal y de última milla, despliegues de Acceso Inalámbrico Fijo (FWA) y datacenters construidos para cargas de trabajo de IA. Está diseñada para aplicarse por igual a un organismo público, una empresa privada, un consorcio de operadores o un vehículo de inversión de capital mixto, e incorpora agentes de IA generativa como parte constitutiva de su arquitectura &mdash; un agente especializado por fase &mdash; siempre bajo un principio permanente de supervisión humana (human-in-the-loop)."
  },
  "fw.f1.quote": {
    "en": "An infrastructure project doesn't fail at implementation: it fails at structuring. The INA Framework exists to fix that before it happens, regardless of the sponsor's nature.",
    "es": "Un proyecto de infraestructura no fracasa en la implementación: fracasa en la estructuración. El Framework de INA existe para resolver eso antes de que ocurra, sin importar la naturaleza del sponsor."
  },
  "fw.f1.quote.cite": {
    "en": "INA Project Structuring Framework&trade; — Executive Summary",
    "es": "INA Project Structuring Framework&trade; — Resumen Ejecutivo"
  },
