  "fw.f1.p1": {
    "en": "Structuring before execution",
    "es": "Estructuración antes de la ejecución"
  },
  "fw.f1.p1.d": {
    "en": "Every relevant design decision (architecture, contracting model, sizing) must be closed before procurement begins, not during it.",
    "es": "Toda decisión de diseño relevante (arquitectura, modelo de contratación, dimensionamiento) debe cerrarse antes de que comience la contratación, no durante ella."
  },
  "fw.f1.p2": {
    "en": "Decision traceability",
    "es": "Trazabilidad de las decisiones"
  },
  "fw.f1.p2.d": {
    "en": "Every scope, budget or schedule definition is documented and linked to who made it and with what information, enabling audit without retroactive reconstruction.",
    "es": "Toda definición de alcance, presupuesto o cronograma se documenta y se vincula a quién la tomó y con qué información, permitiendo auditoría sin reconstrucción retroactiva."
  },
  "fw.f1.p3": {
    "en": "Proportional governance",
    "es": "Gobernanza proporcional"
  },
  "fw.f1.p3.d": {
    "en": "The intensity of control mechanisms is calibrated to the project's risk and size &mdash; avoiding both over-bureaucratization and under-control.",
    "es": "La intensidad de los mecanismos de control se calibra según el riesgo y el tamaño del proyecto &mdash; evitando tanto la sobre-burocratización como el sub-control."
  },
  "fw.f1.p4": {
    "en": "Risk as a design variable",
    "es": "El riesgo como variable de diseño"
  },
  "fw.f1.p4.d": {
    "en": "Technical, budgetary, regulatory and vendor risks are assessed from the diagnostic phase onward, and actively shape the contracting model.",
    "es": "Los riesgos técnicos, presupuestarios, regulatorios y de proveedores se evalúan desde la fase de diagnóstico, y moldean activamente el modelo de contratación."
  },
  "fw.f1.p5": {
    "en": "People-centered adoption",
    "es": "Adopción centrada en las personas"
  },
  "fw.f1.p5.d": {
    "en": "No infrastructure generates value if the operating teams don't adopt it; change management is planned in parallel with implementation, not after it.",
    "es": "Ninguna infraestructura genera valor si los equipos operativos no la adoptan; la gestión del cambio se planifica en paralelo a la implementación, no después."
  },
  "fw.f1.p6": {
    "en": "Generative AI as a constitutive layer",
    "es": "IA generativa como capa constitutiva"
  },
  "fw.f1.p6.d": {
    "en": "AI agents are integral to the methodology, not an accessory: every phase has at least one agent, always under explicit human supervision at gates.",
    "es": "Los agentes de IA son parte integral de la metodología, no un accesorio: cada fase tiene al menos un agente, siempre bajo supervisión humana explícita en los gates."
  },
  "fw.f1.agents.title": {
    "en": "AI Agent Architecture",
    "es": "Arquitectura de Agentes de IA"
  },
  "fw.f1.agents.lede": {
    "en": "One specialized agent per phase, plus a cross-cutting traceability agent. None holds gate-approval authority — that RACI \"Accountable\" role always stays with a human.",
    "es": "Un agente especializado por fase, más un agente transversal de trazabilidad. Ninguno tiene autoridad para aprobar un gate — el rol \"Accountable\" del RACI siempre queda en manos humanas."
  },
