  "risk1.r": {
    "en": "Underestimation of migration costs",
    "es": "Subestimación de costos de migración"
  },
  "risk1.m": {
    "en": "Total-cost model validated in Phase II with external benchmarking",
    "es": "Modelo de costo total validado en Fase II con benchmarking externo"
  },
  "risk2.r": {
    "en": "Delays in the vendor selection process",
    "es": "Demoras en el proceso de selección de proveedores"
  },
  "risk2.m": {
    "en": "Tender/RFP documentation legally pre-approved before publishing the call",
    "es": "Pliego pre-aprobado legalmente antes de publicar la convocatoria"
  },
  "risk3.r": {
    "en": "Single-vendor dependency (vendor lock-in)",
    "es": "Dependencia de un único proveedor (vendor lock-in)"
  },
  "risk3.m": {
    "en": "Contractual portability clauses and code/data ownership provisions",
    "es": "Cláusulas contractuales de portabilidad y titularidad de código/datos"
  },
  "risk4.r": {
    "en": "Low adoption by internal users",
    "es": "Baja adopción por parte de usuarios internos"
  },
  "risk4.m": {
    "en": "Change management plan starting in Phase III, not after delivery",
    "es": "Plan de gestión del cambio desde la Fase III, no después de la entrega"
  },
  "risk5.r": {
    "en": "Vendor SLA non-compliance",
    "es": "Incumplimiento de SLA por el proveedor"
  },
  "risk5.m": {
    "en": "Escalating penalties and measurable indicators built into the tender",
    "es": "Penalidades escalonadas e indicadores medibles incorporados al pliego"
  },
  "risk6.r": {
    "en": "Regulatory changes during execution",
    "es": "Cambios regulatorios durante la ejecución"
  },
  "risk6.m": {
    "en": "Review clause and technical committee with regulatory monitoring",
    "es": "Cláusula de revisión y comité técnico con monitoreo regulatorio"
  },
  "risk7.r": {
    "en": "Errors or inaccuracies in AI agent-generated content (\"hallucinations\")",
    "es": "Errores o imprecisiones en contenido generado por agentes de IA (\"alucinaciones\")"
  },
  "risk7.m": {
    "en": "No AI agent output is final without explicit human validation at the corresponding gate",
    "es": "Ningún output de un agente de IA es definitivo sin validación humana explícita en el gate correspondiente"
  },
  "risk8.r": {
    "en": "Use of the sponsor's sensitive data in AI models without adequate controls",
    "es": "Uso de datos sensibles del sponsor en modelos de IA sin controles adecuados"
  },
  "risk8.m": {
    "en": "Data-handling policy defined in Phase III; controlled-retention environments and confidentiality agreements with AI providers",
    "es": "Política de manejo de datos definida en la Fase III; entornos de retención controlada y acuerdos de confidencialidad con proveedores de IA"
  },
