  "ins1.t": {
    "en": "Why 2026 Is the Inflection Point for AI Infrastructure in Latin America",
    "es": "Por qué 2026 es el punto de inflexión de la infraestructura de IA en América Latina"
  },
  "ins1.d": {
    "en": "Compute demand, power constraints and sovereign strategy are converging faster than most national roadmaps anticipated.",
    "es": "La demanda de cómputo, las restricciones de energía y la estrategia soberana están convergiendo más rápido de lo que anticipaba la mayoría de las hojas de ruta nacionales."
  },
  "ins2.t": {
    "en": "What Development Finance Institutions Are Actually Prioritizing Right Now",
    "es": "Qué están priorizando realmente hoy las instituciones de financiamiento para el desarrollo"
  },
  "ins2.d": {
    "en": "Blended structures and measurable social return are moving up the list — bankability alone is no longer enough.",
    "es": "Las estructuras mixtas y el retorno social medible ganan peso en la lista — la bancabilidad por sí sola ya no alcanza."
  },
  "ins3.t": {
    "en": "Submarine Cable Investment Is Accelerating — Here's Where",
    "es": "La inversión en cables submarinos se acelera — así es el mapa"
  },
  "ins3.d": {
    "en": "New consortium routes are reshaping capacity economics across the region faster than landing-station permits can keep up.",
    "es": "Nuevas rutas de consorcios están reconfigurando la economía de capacidad en la región más rápido de lo que pueden seguir los permisos de estaciones de aterrizaje."
  },
  "ins4.t": {
    "en": "Five Questions Every Ministry Should Ask Before Structuring a Connectivity Project",
    "es": "Cinco preguntas que todo ministerio debería hacerse antes de estructurar un proyecto de conectividad"
  },
  "ins4.d": {
    "en": "The projects that stall at financing usually skipped one of these questions at the opportunity stage.",
    "es": "Los proyectos que se traban en el financiamiento suelen haber saltado una de estas preguntas en la etapa de oportunidad."
  },
  "ins5.t": {
    "en": "AI Advisory Is Becoming a Board-Level Conversation",
    "es": "La asesoría en IA ya es una conversación de directorio"
  },
  "ins5.d": {
    "en": "Governance and ethics are no longer a technical afterthought — they're showing up in the first meeting.",
    "es": "La gobernanza y la ética ya no son un detalle técnico de último momento — aparecen desde la primera reunión."
  },
  "ins6.t": {
    "en": "The Blended Finance Instruments Gaining Traction in 2026",
    "es": "Los instrumentos de finanzas mixtas que ganan tracción en 2026"
  },
  "ins6.d": {
    "en": "A handful of guarantee structures are quietly doing more to unlock private capital than headline concessional funds.",
    "es": "Un puñado de estructuras de garantía están haciendo, silenciosamente, más para destrabar capital privado que los fondos concesionales más visibles."
  },
