const SELECT_OPTIONS = {"type": {"en": ["Government / Regulator", "Development Finance Institution", "Investor / Infrastructure Fund", "Technology Company", "Other"], "es": ["Gobierno / Regulador", "Institución de Financiamiento para el Desarrollo", "Inversor / Fondo de Infraestructura", "Empresa Tecnológica", "Otro"]}};

function applyLang(lang) {
  document.querySelectorAll('[data-i18n]').forEach((el) => {
    const key = el.getAttribute('data-i18n');
    const entry = I18N[key];
    if (entry && entry[lang] != null) {
      el.innerHTML = entry[lang];
    }
  });
  const typeSelect = document.getElementById('type');
  if (typeSelect) {
    const opts = SELECT_OPTIONS.type[lang] || SELECT_OPTIONS.type.en;
    Array.from(typeSelect.options).forEach((opt, i) => {
      if (opts[i]) opt.textContent = opts[i];
    });
  }
  document.documentElement.setAttribute('lang', lang);
  document.querySelectorAll('.lang-btn').forEach((b) => {
    b.classList.toggle('active', b.getAttribute('data-lang') === lang);
  });
  try { localStorage.setItem('ina_lang', lang); } catch (e) {}
}

(function () {
  let saved = 'en';
  try { saved = localStorage.getItem('ina_lang') || 'en'; } catch (e) {}
  document.addEventListener('DOMContentLoaded', () => {
    applyLang(saved);
    document.querySelectorAll('.lang-btn').forEach((b) => {
      b.addEventListener('click', () => applyLang(b.getAttribute('data-lang')));
    });
  });
})();
